const authData = $input.item.json;
const body = authData.body || {};

return {
  json: {
    topic_id: body.topic_id || '',
    content_id: body.content_id || '',
    regenerate_text: body.regenerate_text || false,
    platform: body.platform || '',
    product_name: body.product_name || '',
    topic: body.topic || '',
    campaign_id: body.campaign_id || '',
    content_language: body.content_language || 'English',
    user_id: authData.user_id || ''
  }
};

const params = $('Extract Params').item.json;
const contentRaw = $('Read Content Item').item.json;
const icpRaw = $('Read ICP for Text').item.json;

let item = {};
try { item = Array.isArray(contentRaw) ? contentRaw[0] || {} : contentRaw || {}; } catch(e) { item = {}; }

let icp = {};
try { icp = Array.isArray(icpRaw) ? icpRaw[0] || {} : icpRaw || {}; } catch(e) { icp = {}; }

// Read brand doc summaries
let brandContext = '';
try {
  const brandDocsItems = $('Read Brand Docs for Text').all();
  const docSummary = brandDocsItems
    .map(item => item.json.summary_text || '')
    .filter(Boolean)
    .join('\n---\n')
    .substring(0, 3000);
  if (docSummary) {
    brandContext = '\n\nBRAND DOCUMENT GUIDELINES:\n' + docSummary;
  }
} catch(e) { /* no brand docs */ }

const platform = params.platform || item.platform || 'Instagram';
const lang = params.content_language || 'English';
const currentText = item.content || item.post_text || '';
const topic = params.topic || item.topic || '';
const productName = params.product_name || item.product_name || '';

const platformRules = {
  'LinkedIn': 'LinkedIn post: 1300-1800 characters. Professional thought leadership tone. Include 3-5 relevant hashtags. End with a product CTA. Use line breaks for readability.',
  'Instagram': 'Instagram caption: 150-300 characters. Engaging, emoji-friendly. Include a product CTA. Put 20-30 hashtags in a separate first_comment field (NOT in the caption). Use line breaks.',
  'X': 'X/Twitter thread: 5-7 tweets, each under 280 characters. Punchy, conversational. Product CTA in the last tweet. Number each tweet.',
  'YouTube': 'YouTube video script: 30-60 seconds. Include title, opening hook, 4 scene breakdowns with visual directions, music_mood, thumbnail_concept, and CTA.'
};

const rules = platformRules[platform] || platformRules['Instagram'];

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: 'You are a luxury brand social media copywriter. Generate a replacement post that is different from the current text but maintains the same topic and product focus. Write EXCLUSIVELY in ' + lang + '. Every word must be in ' + lang + '.',
  messages: [{
    role: 'user',
    content: 'CRITICAL LANGUAGE REQUIREMENT: Write ALL content exclusively in ' + lang + '. No mixing languages.\n\nGenerate a NEW replacement post for the platform: ' + platform + '\n\n' + rules + '\n\nTOPIC: ' + topic + '\nPRODUCT: ' + productName + '\n\nCURRENT POST TO REPLACE (write something DIFFERENT):\n' + currentText + '\n\nBUSINESS CONTEXT:\n- Industry: ' + (icp.industry || 'Luxury') + '\n- Target Audience: ' + (icp.target_audience || 'Affluent consumers') + '\n- ICP Summary: ' + (icp.icp_summary || '') + brandContext + '\n\nReturn ONLY a JSON object with these keys:\n- content: the new post text\n- hashtags: array of 3-5 hashtags (strings without #)' + (platform === 'Instagram' ? '\n- first_comment: string with 20-30 hashtags for first comment' : '') + (platform === 'YouTube' ? '\n- title: video title\n- music_mood: mood description\n- thumbnail_concept: thumbnail description' : '') + '\n\nNo markdown. No code fences. Just raw JSON.\n\nREMINDER: ALL content must be in ' + lang + '.'
  }]
});

return {
  json: {
    apiBody: body,
    content_id: params.content_id,
    platform: platform
  }
};

const input = $input.item.json;
const prepData = $('Prepare Text Prompt').item.json;

let raw = '';
try { raw = input.content[0].text; } catch(e) { raw = '{}'; }

let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch(e) {
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try { parsed = JSON.parse(stripped); } catch(e2) { parsed = {}; }
}

const newContent = parsed.content || parsed.post_text || parsed.caption || '';
let hashtags = parsed.hashtags || [];
if (typeof hashtags === 'string') {
  hashtags = hashtags.split(/[,\s]+/).filter(h => h).map(h => h.replace(/^#/, ''));
}
hashtags = hashtags.slice(0, 5);

const updateBody = {
  content: newContent,
  hashtags: hashtags,
  updated_at: new Date().toISOString()
};

if (parsed.first_comment) updateBody.first_comment = parsed.first_comment;

return {
  json: {
    updateBody: JSON.stringify(updateBody),
    content_id: prepData.content_id,
    content: newContent,
    hashtags: hashtags,
    first_comment: parsed.first_comment || null
  }
};

const topicRaw = $input.item.json;
const params = $('Extract Params').item.json;

let topic = {};
try {
  topic = Array.isArray(topicRaw) ? topicRaw[0] || {} : topicRaw || {};
} catch(e) { topic = {}; }

return {
  json: {
    ...topic,
    user_id: params.user_id,
    topic_id: params.topic_id
  }
};

const currentTopic = $('Parse Current Topic').item.json;
const siblingsRaw = $('Read Sibling Topics').item.json;
const icpRaw = $('Read ICP').item.json;

let siblings = [];
try { siblings = Array.isArray(siblingsRaw) ? siblingsRaw : []; } catch(e) { siblings = []; }

let icp = {};
try { icp = Array.isArray(icpRaw) ? icpRaw[0] || {} : icpRaw || {}; } catch(e) { icp = {}; }

// Read brand doc summaries
let brandContext = '';
try {
  const brandDocsItems = $('Read Brand Docs').all();
  const docSummary = brandDocsItems
    .map(item => item.json.summary_text || '')
    .filter(Boolean)
    .join('\n---\n')
    .substring(0, 3000);
  if (docSummary) {
    brandContext = '\n\nBRAND DOCUMENT GUIDELINES:\n' + docSummary;
  }
} catch(e) { /* no brand docs */ }

const siblingTopics = siblings.map(s => s.topic + ' (' + s.content_angle + ')').join(', ');

const dayNames = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
const dayName = dayNames[(currentTopic.day_number || 1) - 1] || 'Day ' + currentTopic.day_number;

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1024,
  system: 'You are a social media content strategist. Generate a replacement topic that is different from existing topics.',
  messages: [{
    role: 'user',
    content: 'Generate 1 NEW replacement topic for ' + dayName + ' (Day ' + currentTopic.day_number + ') of Week ' + currentTopic.week_number + '.\n\nCURRENT TOPIC TO REPLACE: ' + currentTopic.topic + '\n\nOTHER TOPICS THIS WEEK (avoid duplicating): ' + (siblingTopics || 'none') + '\n\nBUSINESS CONTEXT:\n- Industry: ' + (icp.industry || 'General') + '\n- Target Audience: ' + (icp.target_audience || 'General audience') + '\n- Content Pillars: ' + JSON.stringify(icp.content_pillars || []) + brandContext + '\n\nReturn ONLY a single JSON object with keys: topic, description, content_angle, product_name. Must be completely different from the current topic and siblings. No markdown.'
  }]
});

return {
  json: {
    apiBody: body,
    topic_id: currentTopic.topic_id || currentTopic.id,
    user_id: currentTopic.user_id,
    campaign_id: currentTopic.campaign_id,
    week_number: currentTopic.week_number,
    day_number: currentTopic.day_number
  }
};

const input = $input.item.json;
const prepData = $('Prepare Claude Prompt').item.json;

let raw = '';
try { raw = input.content[0].text; } catch(e) { raw = '{}'; }

let newTopic = {};
try {
