return {
  json: {
    updateBody: updateBody,
    topic_id: prepData.topic_id,
    newTopic: newTopic
  }
};

const updated = $input.item.json;
const parseData = $('Parse New Topic').item.json;

let topic = {};
try {
  topic = Array.isArray(updated) ? updated[0] || {} : updated || {};
} catch(e) { topic = {}; }

return {
  json: {
    success: true,
    topic: topic.id ? topic : { ...parseData.newTopic, id: parseData.topic_id }
  }
};

